        String userInput = "rO0ABXNyAC5qYXZheC5tYWlubGFiLk1haWxTY29tZWRldGVjdE1haW4AAAAAAAAAAQIAAHhyACxqYXZhLmxhbmcuRG91YmxlSW50ZWdlchLioKT3gYR4lAgABeA==";

        try {
            byte[] serializedData = javax.xml.bind.DatatypeConverter.parseBase64Binary(userInput);
            ByteArrayInputStream bis = new ByteArrayInputStream(serializedData);
            ObjectInputStream ois = new ObjectInputStream(bis);

            // Deserialize the object
            Object obj = ois.readObject();

            if (obj instanceof String) {
                System.out.println("Deserialized object: " + obj);
            } else {
                System.out.println("Unexpected object type");
            }

        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

